import { useEffect, useState } from "react";
import { NavLink, useNavigate } from "react-router-dom";
import { useAuth } from "../services/AuthContext";

const userLinks = [
  { to: "/dashboard", label: "Overview" },
  { to: "/symptoms", label: "Symptom Checker" },
  { to: "/appointments", label: "Appointments" },
  { to: "/medications", label: "Medication" },
  { to: "/reports", label: "Scan Reports" },
  { to: "/insurance", label: "Insurance" },
  { to: "/stats", label: "Stats" },
  { to: "/assistant", label: "AI Assistant" },
];

const adminLinks = [
  { to: "/admin", label: "Overview" },
  { to: "/admin/users", label: "Users" },
  { to: "/admin/symptoms", label: "Symptoms" },
  { to: "/admin/medications", label: "Medication" },
  { to: "/admin/reports", label: "Reports" },
  { to: "/admin/insurance", label: "Insurance" },
  { to: "/admin/appointments", label: "Appointments" },
  { to: "/admin/logs", label: "Chat Logs" },
  { to: "/admin/analytics", label: "Analytics" },
  { to: "/admin/alerts", label: "Alerts" },
  { to: "/admin/system-control", label: "System Control" },
  { to: "/admin/assistant", label: "AI Assistant" },
];

export default function AppShell({ role, children }) {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const links = role === "admin" ? adminLinks : userLinks;
  const [theme, setTheme] = useState(() => localStorage.getItem("health_assistant_theme") || "light");

  useEffect(() => {
    document.body.dataset.theme = theme;
    localStorage.setItem("health_assistant_theme", theme);
  }, [theme]);

  const handleLogout = () => {
    logout();
    navigate("/login");
  };

  return (
    <div className="shell-root">
      <aside className="sidebar">
        <div className="brand-card glossy-card">
          <span className="eyebrow">Health Care Assistant</span>
          <h1>{role === "admin" ? "Admin Supervisory Portal" : "Patient Portal"}</h1>
          <p>
            {role === "admin"
              ? "Hybrid monitoring access across all modules, with patient diagnosis actions restricted."
              : "Guided care navigation with a central AI companion."}
          </p>
        </div>
        <nav className="nav-stack">
          {links.map((link) => (
            <NavLink key={link.to} to={link.to} className={({ isActive }) => `nav-link${isActive ? " active" : ""}`}>
              {link.label}
            </NavLink>
          ))}
        </nav>
      </aside>
      <div className="shell-main">
        <header className="topbar shell-topbar topbar-glass">
          <div className="brand">
            <h2>{user?.name || "Health Assistant"}</h2>
            <p>{user?.email}</p>
          </div>
          <div className="button-row">
            <button type="button" className="btn btn-secondary" onClick={() => setTheme((current) => (current === "light" ? "dark" : "light"))}>
              {theme === "light" ? "Dark Theme" : "Light Theme"}
            </button>
            <span className="pill">{role === "admin" ? "Supervisory Admin" : "Patient"}</span>
            <button className="btn btn-secondary" onClick={handleLogout}>Logout</button>
          </div>
        </header>
        <main className="page-content">{children}</main>
      </div>
    </div>
  );
}
